import java.io.*;
import java.util.*;

public class Main {
    static class Node {
        int data;
        Node left, right;
        Node(int d) { data = d; }
    }

    // Build tree from level order array where -1 denotes null
    static Node buildTree(int[] arr) {
        if (arr.length == 0 || arr[0] == -1) return null;
        Node root = new Node(arr[0]);
        Queue<Node> q = new ArrayDeque<>();
        q.add(root);
        int i = 1;
        while (i < arr.length && !q.isEmpty()) {
            Node cur = q.poll();
            if (i < arr.length && arr[i] != -1) {
                cur.left = new Node(arr[i]);
                q.add(cur.left);
            }
            i++;
            if (i < arr.length && arr[i] != -1) {
                cur.right = new Node(arr[i]);
                q.add(cur.right);
            }
            i++;
        }
        return root;
    }

    static Node findLCA(Node root, int n1, int n2) {
        if (root == null) return null;
        if (root.data == n1 || root.data == n2) return root;
        Node left = findLCA(root.left, n1, n2);
        Node right = findLCA(root.right, n1, n2);
        if (left != null && right != null) return root;
        return left != null ? left : right;
    }

    public static void main(String[] args) throws Exception {
        // Read entire input as raw string
        String raw = new String(System.in.readAllBytes());
        // Convert escaped "\n" sequences to real newlines
        raw = raw.replace("\\n", "\n");
        // Remove stray double quotes that may appear in some test harnesses
        raw = raw.replace("\"", "");
        BufferedReader br = new BufferedReader(new StringReader(raw));
        StringBuilder sb = new StringBuilder();
        String line;
        // Read number of test cases, skipping empty lines
        while ((line = br.readLine()) != null && line.trim().isEmpty()) {}
        if (line == null) return;
        int T = Integer.parseInt(line.trim());
        while (T-- > 0) {
            // Read N, skipping possible empty lines
            while ((line = br.readLine()) != null && line.trim().isEmpty()) {}
            int N = Integer.parseInt(line.trim());
            // Read array line (may span multiple lines if spaces are irregular)
            while ((line = br.readLine()) != null && line.trim().isEmpty()) {}
            StringTokenizer st = new StringTokenizer(line);
            int[] arr = new int[N];
            for (int i = 0; i < N; i++) {
                if (!st.hasMoreTokens()) {
                    // If not enough tokens on this line, read next line
                    line = br.readLine();
                    st = new StringTokenizer(line);
                }
                arr[i] = Integer.parseInt(st.nextToken());
            }
            // Read n1 and n2 line
            while ((line = br.readLine()) != null && line.trim().isEmpty()) {}
            st = new StringTokenizer(line);
            int n1 = Integer.parseInt(st.nextToken());
            int n2 = Integer.parseInt(st.nextToken());
            Node root = buildTree(arr);
            Node lca = findLCA(root, n1, n2);
            sb.append(lca != null ? lca.data : -1).append('\n');
        }
        System.out.print(sb.toString());
    }
}

